211→/// Convert persisted JSON messages (from session store) to typed `ChatMessage`s.
212→///
213→/// Skips messages that don't have a valid `role` field, logging a warning.
214→/// Metadata fields (`created_at`, `model`, `provider`, `inputTokens`,
215→/// `outputTokens`, `channel`) are silently dropped — they only exist in
216→/// the persisted JSON, not in `ChatMessage`.
217→pub fn values_to_chat_messages(values: &[serde_json::Value]) -> Vec<ChatMessage> {
218→    let mut messages = Vec::with_capacity(values.len());
219→    // Track tool_call IDs emitted by assistant messages so we only include
220→    // tool/tool_result messages that have a matching assistant tool_call.
