222→    // provider API errors.
223→    let mut pending_tool_call_ids: std::collections::HashSet<String> =
224→        std::collections::HashSet::new();
225→    for (i, val) in values.iter().enumerate() {
226→        let Some(role) = val["role"].as_str() else {
227→            tracing::warn!(index = i, "skipping message with missing/invalid role");
228→            continue;
229→        };
230→        match role {
231→            "system" => {
232→                let content = val["content"].as_str().unwrap_or("").to_string();
233→                messages.push(ChatMessage::system(content));
234→            },
235→            "user" => {
236→                let document_context = val["documents"].as_array().and_then(|documents| {
237→                    let mut sections = Vec::new();
238→                    for document in documents {
239→                        let Some(display_name) = document["display_name"].as_str() else {
240→                            continue;
241→                        };
242→                        let Some(mime_type) = document["mime_type"].as_str() else {
243→                            continue;
244→                        };
245→                        let Some(media_ref) = document["media_ref"].as_str() else {
246→                            continue;
247→                        };
248→                        let absolute_path = document_absolute_path_from_media_ref(media_ref);
249→                        sections.push(format!(
250→                            "filename: {display_name}\nmime_type: {mime_type}\nlocal_path: {absolute_path}\nmedia_ref: {media_ref}"
251→                        ));
252→                    }
253→                    if sections.is_empty() {
254→                        None
255→                    } else {
256→                        let mut rendered = vec!["[Inbound documents available]".to_string()];
257→                        rendered.extend(sections);
258→                        Some(rendered.join("\n\n"))
259→                    }
260→                });
261→
262→                // Content can be a string or an array (multimodal).
263→                if let Some(text) = val["content"].as_str() {
264→                    let content = if let Some(ref document_context) = document_context {
265→                        if text.trim().is_empty() {
266→                            document_context.clone()
267→                        } else {
268→                            format!("{text}\n\n{document_context}")
269→                        }
270→                    } else {
271→                        text.to_string()
272→                    };
273→                    messages.push(ChatMessage::user(content));
274→                } else if let Some(arr) = val["content"].as_array() {
275→                    let mut parts: Vec<ContentPart> = arr
276→                        .iter()
277→                        .filter_map(|block| {
278→                            let block_type = block["type"].as_str()?;
279→                            match block_type {
280→                                "text" => {
281→                                    let text = block["text"].as_str()?.to_string();
282→                                    Some(ContentPart::Text(text))
283→                                },
284→                                "image_url" => {

625→        assert!(matches!(msg, ChatMessage::System { content } if content == "You are helpful."));
626→    }
