            }),
            serde_json::json!({"role": "assistant", "content": "done"}),
        ];
        let msgs = values_to_chat_messages(&values);
        assert_eq!(msgs.len(), 2);
        assert!(matches!(&msgs[0], ChatMessage::User { .. }));
        assert!(matches!(&msgs[1], ChatMessage::Assistant { .. }));
    }

