    let values = vec![serde_json::json!({
        "role": "assistant",
        "content": "thinking",
        "tool_calls": [{
            "id": "call_1",
            "type": "function",
            "function": {
                "name": "exec",
                "arguments": "{\"cmd\":\"ls\"}"
            }
        }]
    })];
