use std::pin::Pin;

use {
    async_openai::{
        config::OpenAIConfig,
        types::chat::{
            ChatCompletionRequestAssistantMessageArgs, ChatCompletionRequestMessage,
            ChatCompletionRequestMessageContentPartImage,
            ChatCompletionRequestMessageContentPartText, ChatCompletionRequestSystemMessageArgs,
            ChatCompletionRequestUserMessageArgs, ChatCompletionRequestUserMessageContent,
            ChatCompletionRequestUserMessageContentPart, CreateChatCompletionRequestArgs, ImageUrl,
        },
    },
    async_trait::async_trait,
    futures::StreamExt,
    tokio_stream::Stream,
};

use moltis_agents::model::{
    ChatMessage, CompletionResponse, LlmProvider, StreamEvent, Usage, UserContent,
};

/// Provider backed by the `async-openai` crate.
/// Works with OpenAI and any OpenAI-compatible API (Ollama, vLLM, etc.)
/// via custom base URL.
pub struct AsyncOpenAiProvider {
    model: String,
    client: async_openai::Client<OpenAIConfig>,
    /// Optional alias for metrics differentiation.
    alias: Option<String>,
}

impl AsyncOpenAiProvider {
    pub fn new(api_key: secrecy::Secret<String>, model: String, base_url: String) -> Self {
        use secrecy::ExposeSecret;
        let config = OpenAIConfig::new()
            .with_api_key(api_key.expose_secret())
            .with_api_base(&base_url);
        Self {
            model,
            client: async_openai::Client::with_config(config),
            alias: None,
        }
    }

    /// Create a new provider with a custom alias for metrics.
    pub fn with_alias(
        api_key: secrecy::Secret<String>,
        model: String,
        base_url: String,
        alias: Option<String>,
    ) -> Self {
        use secrecy::ExposeSecret;
        let config = OpenAIConfig::new()
            .with_api_key(api_key.expose_secret())
            .with_api_base(&base_url);
        Self {
            model,
            client: async_openai::Client::with_config(config),
            alias,
        }
    }
}

fn build_messages(messages: &[ChatMessage]) -> anyhow::Result<Vec<ChatCompletionRequestMessage>> {
    let mut out = Vec::new();
    for msg in messages {
        match msg {
            ChatMessage::System { content } => {
                out.push(
                    ChatCompletionRequestSystemMessageArgs::default()
                        .content(content.as_str())
                        .build()?
                        .into(),
                );
            },
            ChatMessage::Assistant { content, .. } => {
                out.push(
                    ChatCompletionRequestAssistantMessageArgs::default()
                        .content(content.as_deref().unwrap_or(""))
                        .build()?
                        .into(),
                );
            },
            ChatMessage::User {
                content: UserContent::Text(text),
            } => {
                out.push(
                    ChatCompletionRequestUserMessageArgs::default()
                        .content(text.as_str())
                        .build()?
                        .into(),
                );
            },
            ChatMessage::User {
                content: UserContent::Multimodal(parts),
            } => {
                let content_parts: Vec<ChatCompletionRequestUserMessageContentPart> = parts
                    .iter()
                    .map(|p| match p {
                        moltis_agents::model::ContentPart::Text(t) => {
                            ChatCompletionRequestUserMessageContentPart::Text(
                                ChatCompletionRequestMessageContentPartText { text: t.clone() },
                            )
                        },
                        moltis_agents::model::ContentPart::Image { media_type, data } => {
                            let data_uri = format!("data:{media_type};base64,{data}");
                            ChatCompletionRequestUserMessageContentPart::ImageUrl(
                                ChatCompletionRequestMessageContentPartImage {
                                    image_url: ImageUrl {
                                        url: data_uri,
                                        detail: None,
                                    },
                                },
                            )
                        },
                    })
                    .collect();
                out.push(ChatCompletionRequestMessage::User(
                    async_openai::types::chat::ChatCompletionRequestUserMessage {
                        content: ChatCompletionRequestUserMessageContent::Array(content_parts),
                        name: None,
                    },
                ));
            },
            ChatMessage::Tool { content, .. } => {
                // async-openai doesn't have a dedicated tool result builder;
                // send as a user message with the tool output.
                out.push(
                    ChatCompletionRequestUserMessageArgs::default()
                        .content(content.as_str())
                        .build()?
                        .into(),
                );
            },
        }
    }
    Ok(out)
}

#[async_trait]
impl LlmProvider for AsyncOpenAiProvider {
    fn name(&self) -> &str {
        self.alias.as_deref().unwrap_or("async-openai")
    }

    fn id(&self) -> &str {
        &self.model
    }

    async fn complete(
        &self,
        messages: &[ChatMessage],
        _tools: &[serde_json::Value],
    ) -> anyhow::Result<CompletionResponse> {
        let oai_messages = build_messages(messages)?;

        let request = CreateChatCompletionRequestArgs::default()
            .model(&self.model)
            .messages(oai_messages)
            .build()?;

        let response = self.client.chat().create(request).await?;

        let text = response
            .choices
            .first()
            .and_then(|c| c.message.content.clone());

        let usage = response
            .usage
            .as_ref()
            .map(|u| Usage {
                input_tokens: u.prompt_tokens,
                output_tokens: u.completion_tokens,
                ..Default::default()
            })
            .unwrap_or_default();

        Ok(CompletionResponse {
            text,
            tool_calls: vec![],
            usage,
        })
    }

    #[allow(clippy::collapsible_if)]
    fn stream(
        &self,
        messages: Vec<ChatMessage>,
    ) -> Pin<Box<dyn Stream<Item = StreamEvent> + Send + '_>> {
        Box::pin(async_stream::stream! {
            let oai_messages = match build_messages(&messages) {
                Ok(m) => m,
                Err(e) => {
                    yield StreamEvent::Error(format!("{e}"));
                    return;
                }
            };

            let request = match CreateChatCompletionRequestArgs::default()
                .model(&self.model)
                .messages(oai_messages)
                .build()
            {
                Ok(r) => r,
                Err(e) => {
                    yield StreamEvent::Error(format!("{e}"));
                    return;
                }
            };

            let mut stream = match self.client.chat().create_stream(request).await {
                Ok(s) => s,
                Err(e) => {
                    yield StreamEvent::Error(format!("{e}"));
                    return;
                }
            };

            while let Some(result) = stream.next().await {
                match result {
                    Ok(response) => {
                        for choice in &response.choices {
                            if let Some(ref content) = choice.delta.content {
                                if !content.is_empty() {
                                    yield StreamEvent::Delta(content.clone());
                                }
                            }
                        }
                        if let Some(ref u) = response.usage {
                            yield StreamEvent::Done(Usage {
                                input_tokens: u.prompt_tokens,
                                output_tokens: u.completion_tokens,
                                ..Default::default()
                            });
                            return;
                        }
                    }
                    Err(e) => {
                        yield StreamEvent::Error(format!("{e}"));
                        return;
                    }
                }
            }

            yield StreamEvent::Done(Usage::default());
        })
    }
}

//! Chat template formatting for various model families.
//!
//! Different LLM families use different prompt formats. This module provides
//! template formatting for Llama3, ChatML (Qwen/Kimi), Mistral, and DeepSeek.

use moltis_agents::model::{ChatMessage, UserContent};

/// Hint for which chat template to use.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Default)]
pub enum ChatTemplateHint {
    /// Try to use the model's embedded template, fall back to ChatML.
    #[default]
    Auto,
    /// Llama 3 format: `<|begin_of_text|><|start_header_id|>system<|end_header_id|>...`
    Llama3,
    /// ChatML format: `<|im_start|>system\n...<|im_end|>` (Qwen, Kimi, Yi)
    ChatML,
    /// Mistral format: `[INST] ... [/INST]`
    Mistral,
    /// DeepSeek format (similar to ChatML with minor differences)
    DeepSeek,
}

impl ChatTemplateHint {
    /// Parse from string (for config).
    #[must_use]
    pub fn parse(s: &str) -> Self {
        match s.to_lowercase().as_str() {
            "llama3" | "llama" => Self::Llama3,
            "chatml" | "qwen" | "kimi" | "yi" => Self::ChatML,
            "mistral" => Self::Mistral,
            "deepseek" => Self::DeepSeek,
            _ => Self::Auto,
        }
    }
}

/// Extract role and content strings from a `ChatMessage`.
fn role_content(msg: &ChatMessage) -> (&str, &str) {
    match msg {
        ChatMessage::System { content } => ("system", content.as_str()),
        ChatMessage::User { content } => match content {
            UserContent::Text(text) => ("user", text.as_str()),
            UserContent::Multimodal(_) => ("user", ""),
        },
        ChatMessage::Assistant { content, .. } => ("assistant", content.as_deref().unwrap_or("")),
        ChatMessage::Tool { content, .. } => ("tool", content.as_str()),
    }
}

/// Format messages using the specified chat template.
#[must_use]
pub fn format_messages(messages: &[ChatMessage], hint: ChatTemplateHint) -> String {
    match hint {
        ChatTemplateHint::Auto | ChatTemplateHint::ChatML => format_chatml(messages),
        ChatTemplateHint::Llama3 => format_llama3(messages),
        ChatTemplateHint::Mistral => format_mistral(messages),
        ChatTemplateHint::DeepSeek => format_deepseek(messages),
    }
}

/// Format using ChatML template (Qwen, Kimi, Yi).
///
/// ```text
/// <|im_start|>system
/// {system_message}<|im_end|>
/// <|im_start|>user
/// {user_message}<|im_end|>
/// <|im_start|>assistant
/// ```
fn format_chatml(messages: &[ChatMessage]) -> String {
    let mut output = String::new();

    for msg in messages {
        let (role, content) = role_content(msg);

        output.push_str("<|im_start|>");
        output.push_str(role);
        output.push('\n');
        output.push_str(content);
        output.push_str("<|im_end|>\n");
    }

    // Add the assistant prefix for generation
    output.push_str("<|im_start|>assistant\n");
    output
}

/// Format using Llama 3 template.
///
/// ```text
/// <|begin_of_text|><|start_header_id|>system<|end_header_id|>
///
/// {system_message}<|eot_id|><|start_header_id|>user<|end_header_id|>
///
/// {user_message}<|eot_id|><|start_header_id|>assistant<|end_header_id|>
/// ```
fn format_llama3(messages: &[ChatMessage]) -> String {
    let mut output = String::from("<|begin_of_text|>");

    for msg in messages {
        let (role, content) = role_content(msg);

        output.push_str("<|start_header_id|>");
        output.push_str(role);
        output.push_str("<|end_header_id|>\n\n");
        output.push_str(content);
        output.push_str("<|eot_id|>");
    }

    // Add the assistant prefix for generation
    output.push_str("<|start_header_id|>assistant<|end_header_id|>\n\n");
    output
}

/// Format using Mistral template.
///
/// ```text
/// <s>[INST] {system_message}
///
/// {user_message} [/INST]
/// ```
fn format_mistral(messages: &[ChatMessage]) -> String {
    let mut output = String::from("<s>");
    let mut in_inst = false;
    let mut system_content = String::new();

    for msg in messages {
        let (role, content) = role_content(msg);

        match role {
            "system" => {
                // System message is prepended to the first user message
                system_content = content.to_string();
            },
            "user" => {
                if in_inst {
                    output.push_str("</s>");
                }
                output.push_str("[INST] ");
                if !system_content.is_empty() {
                    output.push_str(&system_content);
                    output.push_str("\n\n");
                    system_content.clear();
                }
                output.push_str(content);
                output.push_str(" [/INST]");
                in_inst = true;
            },
            "assistant" => {
                output.push_str(content);
                in_inst = false;
            },
            _ => {},
        }
    }

    output
}

/// Format using DeepSeek template (similar to ChatML).
///
/// ```text
/// <|begin▁of▁sentence|>system
/// {system_message}
/// <|User|>{user_message}
/// <|Assistant|>
/// ```
fn format_deepseek(messages: &[ChatMessage]) -> String {
    let mut output = String::from("<|begin▁of▁sentence|>");

    for msg in messages {
        let (role, content) = role_content(msg);

        match role {
            "system" => {
                output.push_str("system\n");
                output.push_str(content);
                output.push('\n');
            },
            "user" => {
                output.push_str("<|User|>");
                output.push_str(content);
                output.push('\n');
            },
            "assistant" => {
                output.push_str("<|Assistant|>");
                output.push_str(content);
                output.push('\n');
            },
            _ => {},
        }
    }

    // Add the assistant prefix for generation
    output.push_str("<|Assistant|>");
    output
}

#[cfg(test)]
mod tests {
    use super::*;

    fn simple_messages() -> Vec<ChatMessage> {
        vec![
            ChatMessage::system("You are a helpful assistant."),
            ChatMessage::user("Hello!"),
        ]
    }

    fn multi_turn_messages() -> Vec<ChatMessage> {
        vec![
            ChatMessage::system("You are a helpful assistant."),
            ChatMessage::user("What is 2+2?"),
            ChatMessage::assistant("4"),
            ChatMessage::user("And 3+3?"),
